 /**
  * File watcher. Tracks a set of watched paths and signals when one changes via
- * notifyChanged(). Automatic change detection is not wired up yet.
+ * notifyChanged(). Polls each watched path every POLL_MS milliseconds.
  */

+import { stat } from 'node:fs/promises';
 import { emit } from './bus.js';

+const POLL_MS = 1000;
+
 const watched = new Set<string>();
+const mtimes = new Map<string, number>();
+let pollTimer: ReturnType<typeof setInterval> | null = null;
+
+async function pollOnce(): Promise<void> {
+  for (const filePath of watched) {
+    try {
+      const s = await stat(filePath);
+      const prev = mtimes.get(filePath);
+      if (prev !== undefined && s.mtimeMs !== prev) {
+        notifyChanged(filePath);
+      }
+      mtimes.set(filePath, s.mtimeMs);
+    } catch {
+      // file may not exist or was deleted; skip this cycle
+    }
+  }
+}
+
+function startPolling(): void {
+  if (pollTimer !== null) return;
+  pollTimer = setInterval(() => { void pollOnce(); }, POLL_MS);
+  pollTimer.unref();
+}
+
+function stopPolling(): void {
+  if (pollTimer === null) return;
+  clearInterval(pollTimer);
+  pollTimer = null;
+}

 /** Register a path to be watched for changes. */
 export function watch(filePath: string): void {
   watched.add(filePath);
+  // seed mtime so first poll doesn't false-fire
+  stat(filePath).then(s => {
+    if (!mtimes.has(filePath)) mtimes.set(filePath, s.mtimeMs);
+  }).catch(() => {});
+  startPolling();
 }

 /** Stop watching a path. */
 export function unwatch(filePath: string): void {
   watched.delete(filePath);
+  mtimes.delete(filePath);
+  if (watched.size === 0) stopPolling();
 }

 /** Currently-watched paths (snapshot). */

