+/**
+ * Metrics feature-flag helpers.
+ *
+ * METRICS_ENABLED  – set to "false" or "0" to disable metrics (default: true)
+ * METRICS_SAMPLE_RATE – float in [0, 1] controlling the sampling fraction (default: 1.0)
+ */
+
+function parseBool(raw: string | undefined, defaultVal: boolean): boolean {
+  if (raw === undefined) return defaultVal;
+  return raw !== 'false' && raw !== '0';
+}
+
+function parseFloat_(raw: string | undefined, defaultVal: number): number {
+  if (raw === undefined) return defaultVal;
+  const v = parseFloat(raw);
+  return isNaN(v) ? defaultVal : v;
+}
+
+/** Returns true unless metrics have been explicitly disabled via METRICS_ENABLED=false|0. */
+export function metricsEnabled(): boolean {
+  return parseBool(process.env.METRICS_ENABLED, true);
+}
+
+/** Returns the sampling rate from METRICS_SAMPLE_RATE, defaulting to 1.0. */
+export function sampleRate(): number {
+  return parseFloat_(process.env.METRICS_SAMPLE_RATE, 1.0);
+}

